(async () => {
  const DATA_URI = "data:image/png;base64,";
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
  const log = (...args) => console.log('[gemini-reference-upload]', ...args);
  const attachmentSelector = [
    '.attachment-preview-wrapper',
    '.file-preview-container',
    '.file-preview-chip',
    'img[aria-label="Image preview"]',
    '[aria-label*="Remove file" i]',
    '[aria-label*="Remove image" i]',
    '[aria-label*="Remove" i]',
    '[data-testid*="attachment" i]',
    '[data-test-id*="attachment" i]',
    '[class*="attachment" i]',
    '[class*="file-preview" i]',
    'img[src^="blob:"]'
  ].join(', ');

  const dataUriToFile = async (dataUri, name) => {
    const res = await fetch(dataUri);
    const blob = await res.blob();
    return new File([blob], name, { type: blob.type || 'image/png', lastModified: Date.now() });
  };

  const file = await dataUriToFile(DATA_URI, 'automa-reference.png');
  log('prepared file', file.name, file.type, file.size);

  const makeDataTransfer = () => {
    const dt = new DataTransfer();
    dt.items.add(file);
    return dt;
  };

  const visible = (el) => {
    if (!el || !(el instanceof Element)) return false;
    const rect = el.getBoundingClientRect();
    const style = getComputedStyle(el);
    return rect.width > 0 && rect.height > 0 && style.visibility !== 'hidden' && style.display !== 'none';
  };

  const waitForAttachment = async (timeout = 5000) => {
    const start = Date.now();
    while (Date.now() - start < timeout) {
      if (document.querySelector(attachmentSelector)) return true;
      await sleep(250);
    }
    return false;
  };

  const input = document.querySelector('input[type="file"], input[accept*="image" i]');
  if (input) {
    const dt = makeDataTransfer();
    input.files = dt.files;
    input.dispatchEvent(new Event('input', { bubbles: true }));
    input.dispatchEvent(new Event('change', { bubbles: true }));
    log('tried input[type=file]');
    if (await waitForAttachment(5000)) {
      automaNextBlock();
      return;
    }
  }

  const selectors = [
    'input-container',
    'input-area-v2',
    'chat-window',
    'rich-textarea .ql-editor[contenteditable="true"]',
    'div.ql-editor[contenteditable="true"]',
    '[contenteditable="true"]',
    'main',
    'body'
  ];
  const targets = Array.from(new Set(selectors.flatMap((sel) => Array.from(document.querySelectorAll(sel))))).filter(visible);
  if (targets.length === 0) throw new Error('No visible Gemini drop targets found');
  log('drop targets', targets.map((el) => el.tagName.toLowerCase() + (el.className ? '.' + String(el.className).split(/\s+/).slice(0, 2).join('.') : '')).join(' | '));

  for (const target of targets) {
    try {
      target.focus?.();
      target.scrollIntoView?.({ block: 'center', inline: 'center' });
      const dt = makeDataTransfer();
      for (const type of ['pointerenter', 'mouseenter', 'dragenter', 'dragover', 'drop']) {
        const ev = type.startsWith('drag') || type === 'drop'
          ? new DragEvent(type, { bubbles: true, cancelable: true, composed: true, dataTransfer: dt })
          : new MouseEvent(type, { bubbles: true, cancelable: true, composed: true });
        target.dispatchEvent(ev);
        document.dispatchEvent(ev);
        await sleep(120);
      }
      log('tried drop on', target.tagName.toLowerCase());
      if (await waitForAttachment(2500)) {
        log('attachment detected after drop');
        automaNextBlock();
        return;
      }
    } catch (err) {
      log('drop target failed', err && err.message ? err.message : err);
    }
  }

  const editor = document.querySelector('rich-textarea .ql-editor[contenteditable="true"], div.ql-editor[contenteditable="true"], [contenteditable="true"]');
  if (editor) {
    editor.focus();
    const dt = makeDataTransfer();
    const paste = new ClipboardEvent('paste', { bubbles: true, cancelable: true, composed: true, clipboardData: dt });
    editor.dispatchEvent(paste);
    document.dispatchEvent(paste);
    log('tried synthetic paste');
    if (await waitForAttachment(5000)) {
      automaNextBlock();
      return;
    }
  }

  throw new Error('Gemini did not accept synthetic file upload. Automa cannot access the native file chooser here; use the Playwright workflow for reliable upload.');
})().catch((err) => {
  console.error('[gemini-reference-upload] failed', err);
  throw err;
});
